module RefModule (clk, rst, en, d, q);
   input clk, rst, en;
   input [3:0] d;
   output [3:0] q;
   reg [3:0] q;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
      if (rst)
         q <= 4'b0000;
      else if (en)
         q <= d;
   end
endmodule
